+import { describe, it, expect, beforeEach, vi } from 'vitest';
+import { EventBus } from '../../src/events/event-bus.js';
+import {
+  WebhookHandler,
+  resetWebhookIdCounters,
+  type WebhookSender,
+} from '../../src/notifications/webhook-handler.js';
+import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
+
+function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
+  return {
+    type: 'order:created',
+    order: {
+      id: 'order-1',
+      userId: 'user-1',
+      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
+      total: 20,
+      status: 'pending',
+      createdAt: new Date('2026-01-01'),
+      updatedAt: new Date('2026-01-01'),
+    },
+    user: {
+      id: 'user-1',
+      name: 'Alice',
+      email: 'alice@example.com',
+      role: 'member',
+      createdAt: new Date('2026-01-01'),
+      updatedAt: new Date('2026-01-01'),
+    },
+    timestamp: new Date('2026-01-01'),
+    ...overrides,
+  };
+}
+
+function makeStatusChangedEvent(
+  overrides: Partial<OrderStatusChangedEvent> & { previousStatus: string; newStatus: string },
+): OrderStatusChangedEvent {
+  return {
+    type: 'order:status-changed',
+    order: {
+      id: 'order-1',
+      userId: 'user-1',
+      items: [],
+      total: 20,
+      status: overrides.newStatus as OrderStatusChangedEvent['order']['status'],
+      createdAt: new Date('2026-01-01'),
+      updatedAt: new Date('2026-01-01'),
+    },
+    previousStatus: overrides.previousStatus,
+    newStatus: overrides.newStatus,
+    timestamp: new Date('2026-01-01'),
+    ...overrides,
+  };
+}
+
+describe('WebhookHandler', () => {
+  let eventBus: EventBus;
+  let sender: WebhookSender;
+  let handler: WebhookHandler;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    statusChangeCallbacks.clear();
+    sender = vi.fn().mockResolvedValue(true);
+    handler = new WebhookHandler(eventBus, sender);
+    resetWebhookIdCounters();
+  });
+
+  // ---------------------------------------------------------------------------
+  // Registry
+  // ---------------------------------------------------------------------------
+  describe('webhook registry', () => {
+    it('should register a webhook and return its registration', () => {
+      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');
+
+      expect(reg.url).toBe('https://example.com/hook');
+      expect(reg.eventType).toBe('order:created');
+      expect(reg.id).toBeDefined();
