+        expect.objectContaining({
+          type: 'order:created',
+          orderId: 'order-1',
+          total: 20,
+        }),
+      );
+    });
+
+    it('should dispatch to multiple webhooks for the same event', async () => {
+      handler.registerWebhook('https://a.com/hook', 'order:created');
+      handler.registerWebhook('https://b.com/hook', 'order:created');
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(sender).toHaveBeenCalledTimes(2);
+    });
+
+    it('should not dispatch to webhooks registered for other event types', async () => {
+      handler.registerWebhook('https://a.com/hook', 'order:status-changed');
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(sender).not.toHaveBeenCalled();
+    });
+
+    it('should record delivery on successful dispatch', async () => {
+      handler.registerWebhook('https://a.com/hook', 'order:created');
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const deliveries = handler.getDeliveries();
+      expect(deliveries).toHaveLength(1);
+      expect(deliveries[0]?.status).toBe('success');
+      expect(deliveries[0]?.url).toBe('https://a.com/hook');
+      expect(deliveries[0]?.eventType).toBe('order:created');
+    });
+
+    it('should include order details in the payload', async () => {
+      handler.registerWebhook('https://a.com/hook', 'order:created');
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const delivery = handler.getDeliveries()[0]!;
+      expect(delivery.payload).toMatchObject({
+        type: 'order:created',
+        orderId: 'order-1',
+        userId: 'user-1',
+        total: 20,
+        status: 'pending',
+      });
