/**
 * Webhook notification handler — dispatches HTTP callbacks to registered
 * URLs when order lifecycle events occur.
 *
 * Integrates with the existing notification architecture using BOTH patterns:
 * - EventBus subscription for order:created events
 * - CallbackRegistry for order:status-changed events
 *
 * This mirrors how NotificationService and EmailNotificationHandler register
 * their handlers (see notification.service.ts for the mixed-pattern discussion).
 *
 * Depends on:
 * - EventBus (event system) for order creation events
 * - CallbackRegistry (direct callbacks) for status change events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: Record<string, unknown>;
  status: 'success' | 'failure';
  deliveredAt: Date;
}

export type WebhookSender = (url: string, payload: Record<string, unknown>) => Promise<boolean>;

/**
 * Default sender that performs an HTTP POST (stubbed for this demo).
 * In production this would use fetch/axios; here it always succeeds so
 * the handler can be tested without network dependencies.
 */
const defaultSender: WebhookSender = async () => true;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private sender: WebhookSender;

  constructor(private eventBus: EventBus, sender?: WebhookSender) {
    this.sender = sender ?? defaultSender;
    this.registerHandlers();
  }

  // ---------------------------------------------------------------------------
  // Webhook registry
  // ---------------------------------------------------------------------------

  /**
   * Register an external URL to receive callbacks for a specific event type.
   * Returns an unregister function.
   */
  registerWebhook(url: string, eventType: EventType): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} -> ${url} for ${eventType}`);
    return registration;
  }

  /**
   * Remove a webhook registration by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  // ---------------------------------------------------------------------------
  // Delivery log
  // ---------------------------------------------------------------------------

  /** Get all delivery records. */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /** Get deliveries for a specific webhook. */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /** Get the count of deliveries. */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /** Clear all registrations and deliveries (useful for testing). */
  clear(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  // ---------------------------------------------------------------------------
  // Event handlers (dual-pattern)
  // ---------------------------------------------------------------------------

  /**
   * Register event handlers following the existing dual-pattern approach.
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.dispatchWebhooks('order:created', {
        type: event.type,
        orderId: event.order.id,
        userId: event.order.userId,
        items: event.order.items,
        total: event.order.total,
        status: event.order.status,
        timestamp: event.timestamp.toISOString(),
      });
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.dispatchWebhooks('order:status-changed', {
        type: event.type,
        orderId: event.order.id,
        userId: event.order.userId,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
        timestamp: event.timestamp.toISOString(),
      });
    });
  }

  /**
   * Dispatch payloads to all webhooks registered for the given event type.
   */
  private async dispatchWebhooks(
    eventType: EventType,
    payload: Record<string, unknown>,
  ): Promise<void> {
    const targets = this.registrations.filter((r) => r.eventType === eventType);

    for (const target of targets) {
      let status: 'success' | 'failure' = 'failure';
      try {
        const ok = await this.sender(target.url, payload);
        status = ok ? 'success' : 'failure';
      } catch {
        status = 'failure';
      }

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: target.id,
        url: target.url,
        eventType,
        payload,
        status,
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);
      this.logger.info(
        `Webhook delivered: ${delivery.id} to ${target.url} (${status})`,
      );
    }
  }
}

