    ...overrides,
  };
}

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let sender: WebhookSender;
  let handler: WebhookHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    sender = vi.fn().mockResolvedValue(true);
    handler = new WebhookHandler(eventBus, sender);
    resetWebhookIdCounters();
  });

  // ---------------------------------------------------------------------------
  // Registry
  // ---------------------------------------------------------------------------
  describe('webhook registry', () => {
    it('should register a webhook and return its registration', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.id).toBeDefined();
    });

    it('should list all registrations', () => {
      handler.registerWebhook('https://a.com', 'order:created');
      handler.registerWebhook('https://b.com', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook('https://a.com', 'order:created');
      handler.registerWebhook('https://b.com', 'order:status-changed');
      handler.registerWebhook('https://c.com', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook('https://a.com', 'order:created');
      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // order:created dispatch (EventBus pattern)
  // ---------------------------------------------------------------------------
  describe('order:created webhook dispatch', () => {
    it('should dispatch to registered webhooks on order created', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender).toHaveBeenCalledOnce();
      expect(sender).toHaveBeenCalledWith(
        'https://a.com/hook',
        expect.objectContaining({
          type: 'order:created',
          orderId: 'order-1',
          total: 20,
        }),
      );
    });

    it('should dispatch to multiple webhooks for the same event', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender).toHaveBeenCalledTimes(2);
    });

    it('should not dispatch to webhooks registered for other event types', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender).not.toHaveBeenCalled();
    });

    it('should record delivery on successful dispatch', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('success');
      expect(deliveries[0]?.url).toBe('https://a.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:created');
    });

    it('should include order details in the payload', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const delivery = handler.getDeliveries()[0]!;
      expect(delivery.payload).toMatchObject({
        type: 'order:created',
        orderId: 'order-1',
        userId: 'user-1',
        total: 20,
        status: 'pending',
      });
      expect(delivery.payload['items']).toBeDefined();
    });
  });

  // ---------------------------------------------------------------------------
  // order:status-changed dispatch (CallbackRegistry pattern)
  // ---------------------------------------------------------------------------
  describe('order:status-changed webhook dispatch', () => {
    it('should dispatch to registered webhooks on status change', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:status-changed');

      statusChangeCallbacks.notify(
        makeStatusChangedEvent({ previousStatus: 'pending', newStatus: 'confirmed' }),
      );

      // dispatchWebhooks is async; give it a tick to resolve
      await new Promise((r) => setTimeout(r, 0));

      expect(sender).toHaveBeenCalledOnce();
      expect(sender).toHaveBeenCalledWith(
        'https://a.com/hook',
        expect.objectContaining({
          type: 'order:status-changed',
          orderId: 'order-1',
          previousStatus: 'pending',
          newStatus: 'confirmed',
        }),
      );
    });

    it('should record delivery for status change webhooks', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:status-changed');

      statusChangeCallbacks.notify(
        makeStatusChangedEvent({ previousStatus: 'pending', newStatus: 'confirmed' }),
      );

      await new Promise((r) => setTimeout(r, 0));

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('success');
      expect(deliveries[0]?.eventType).toBe('order:status-changed');
    });
  });

  // ---------------------------------------------------------------------------
  // Failure handling
  // ---------------------------------------------------------------------------
  describe('delivery failure handling', () => {
    it('should record failure when sender returns false', async () => {
      (sender as ReturnType<typeof vi.fn>).mockResolvedValue(false);
      handler.registerWebhook('https://a.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
    });

    it('should record failure when sender throws', async () => {
      (sender as ReturnType<typeof vi.fn>).mockRejectedValue(new Error('network error'));
      handler.registerWebhook('https://a.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
    });
  });

  // ---------------------------------------------------------------------------
  // Delivery management
  // ---------------------------------------------------------------------------
  describe('delivery management', () => {
    it('should count deliveries', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');

      expect(handler.getDeliveryCount()).toBe(0);
      await eventBus.emit(makeOrderCreatedEvent());
      expect(handler.getDeliveryCount()).toBe(1);
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg = handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForWebhook(reg.id)).toHaveLength(1);
    });

    it('should clear all data', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clear();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });
});
